const Q_BIOLOGY_2000=[{"id": "objective>Biology>2000>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part that will develop into an organ for feeling is labelled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the antenna. It is a sensory appendage attached to the head of a butterfly. It is used for the sense of smell and balance.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2000>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question.  <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The part labelled II is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">silk thread </div>", "<div style=\"font-family:Cambria;font-size:17px;\">thorax</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fore wing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">anchor </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The silk thread is produced as a thick liquid, excreted through glands near the mouth, which is then spun into a thread by a spinneret located behind the jaws.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2000>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following features are all associated with monocot?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Fibrous root system, branched network of veins and one seed leaf </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Fibrous root system, two seed leaves and floral parts in threes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">One seed leaf, petals in threes or groups of threes and parallel venation of leaves</div>", "<div style=\"font-family:Cambria;font-size:17px;\">One seed leaf, net-veined leaves and petals in threes or multiples of three</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Feature </td><td style=\"border:1px solid black;text-align:center;\">In monocots</td><td style=\"border:1px solid black;text-align:center;\">In dicots <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Number of parts of each flower</td><td style=\"border:1px solid black;text-align:center;\">in threes(flowers are trimerous)</td><td style=\"border:1px solid black;text-align:center;\">in fours or fives (tetramerous or pentamerous) <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Number of furrows or pores in pollen\t</td><td style=\"border:1px solid black;text-align:center;\">one\t</td><td style=\"border:1px solid black;text-align:center;\">three <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Number of cotyledons (leaves in the seed)\t</td><td style=\"border:1px solid black;text-align:center;\">one\t</td><td style=\"border:1px solid black;text-align:center;\">two <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Arrangement of vascular bundles in the stem\t</td><td style=\"border:1px solid black;text-align:center;\">scattered</td><td style=\"border:1px solid black;text-align:center;\">\tin concentric circles <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Roots\t</td><td style=\"border:1px solid black;text-align:center;\">are adventitious\t</td><td style=\"border:1px solid black;text-align:center;\">develop from the radicle <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Arrangement of major leaf veins\t</td><td style=\"border:1px solid black;text-align:center;\">parallel\t</td><td style=\"border:1px solid black;text-align:center;\">reticulate</td></tr></table></div> <br/> Monocots, or monocotyledons, are a group of flowering plants that are characterized by having one seed leaf or cotyledon, petals in threes or groups of threes, and parallel venation of leaves. Therefore, the features associated with monocots are one seed leaf, petals in threes or groups of threes and parallel venation of leaves.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2000>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The set of fins that controls steering, balancing  and change of direction and pitch in fish is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dorsal and anal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pectoral and pelvic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">caudal and dorsal </div>", "<div style=\"font-family:Cambria;font-size:17px;\">anal and pelvic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pectoral and pelvic fins in fish are responsible for steering, balancing, and changing direction and pitch. The pectoral fins are located on either side of the fish, just behind the gills, and are used for steering and maintaining balance. The pelvic fins, located on the underside of the fish, help with up and down movement and turning.</div>", "topic": "STRUCTURAL/BEHAVIOURAL ADAPTATIONS OF VERTEBRATES : BONY FISH"}, {"id": "objective>Biology>2000>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most recently evolved structure in animals is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hair</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cilium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">scale</div>", "<div style=\"font-family:Cambria;font-size:17px;\">feather</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hair is the most recently evolved structures in animals. </div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2000>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Coelom is absent in the class of animals termed </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mollusca </div>", "<div style=\"font-family:Cambria;font-size:17px;\">reptilia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">arthropoda</div>", "<div style=\"font-family:Cambria;font-size:17px;\">coelenterata</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Coelom, a fluid-filled body cavity, is absent in the class of animals termed Coelenterata (also known as Cnidaria). This group includes animals like jellyfish and sea anemones. They have a simpler body structure compared to coelomates, with a single opening serving as both mouth and anus.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>2000>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A characteristic feature of vertebrates that is unique to mammals is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the presence of pentadactyl limbs </div>", "<div style=\"font-family:Cambria;font-size:17px;\">parental care</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the possession of scrotum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pulmonary circulation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The possession of a scrotum is a characteristic feature that is unique to mammals. The scrotum is an external pouch of skin and muscle that contains the testes. It is not found in other vertebrates. While other options like pentadactyl limbs and pulmonary circulation are found in other vertebrates as well, and parental care is not exclusive to mammals.</div>", "topic": "EVOLUTION AMONG THE FOLLOWING : ANIMALIA"}, {"id": "objective>Biology>2000>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The order in which organic evolution has progressed in plants is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thallophyta, schizophyta, bryophyta, pteridophyta and spermatophyta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">schizophyta, thallophyta, bryophyta, pteridophyta and spermatophyta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pteridophyta, spermatophyta, thallophyta, schizophyta and bryophyta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bryophyta, pteridophyta, spermatophyta, thallophyta and schizophyta</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The order of organic evolution in plants is believed to have progressed from simpler to more complex forms. The correct order is Schizophyta (simplest bacteria), Thallophyta (algae and fungi), Bryophyta (mosses and liverworts), Pteridophyta (ferns and their relatives), and Spermatophyta (seed plants, including gymnosperms and angiosperms).</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2000>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which part of the human body does the secretion of the growth hormone occur?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Head region</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Waist region </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neck region </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gonads</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The growth hormone, also known as somatotropin, is secreted by the pituitary gland, which is located at the base of the brain in the head region. This hormone plays a crucial role in cell reproduction, cell regeneration, and growth in humans.</div>", "topic": "COORDINATION AND CONTROL : HORMONAL CONTROL"}, {"id": "objective>Biology>2000>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The parts labelled I and II make up the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glomerulus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">convoluted tubules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">malpighian body</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bowman's capsule</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Malpighian body, also known as the renal corpuscle, is a key component of the nephron in the kidney. It consists of the glomerulus, a network of capillaries where blood filtration occurs, and Bowman's capsule, a cup-shaped structure that surrounds the glomerulus and collects the filtrate. This structure initiates the process of urine formation through blood filtration in the kidneys. <br/> <img src=\"2000/GDKTCR.png\" style=\"position:relative;max-width:100%;\"/> <br/> </div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2000>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The mammals, reabsorption of salt takes place in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Reabsorption of salt takes place in the proximal convoluted tubule.</div>", "topic": "EXCRETION : EXCRETORY MECHANISMS"}, {"id": "objective>Biology>2000>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The part of the brain that controls body posture in mammals is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">thalamus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cerebellum</div>", "<div style=\"font-family:Cambria;font-size:17px;\">spinal cord</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cerebrum</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The cerebellum is the part of the brain that controls body posture in mammals. It is responsible for coordinating voluntary movements, balance, muscle coordination, and body posture. The thalamus is involved in sensory and motor signal relay and the regulation of consciousness and sleep. The spinal cord is the main pathway for information connecting the brain and peripheral nervous system. The cerebrum is responsible for higher brain functions such as thought and action.</div>", "topic": "COORDINATION AND CONTROL : NERVOUS COORDINATION"}, {"id": "objective>Biology>2000>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Peripheral arrangement of vascular tissues in dicots is a characteristic of the internal structure of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">leaf</div>", "<div style=\"font-family:Cambria;font-size:17px;\">petiole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">stem</div>", "<div style=\"font-family:Cambria;font-size:17px;\">root</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The peripheral arrangement of vascular tissues is a characteristic of the internal structure of the stem in dicots. In dicot stems, the vascular bundles (xylem, phloem, cambium) are arranged in a ring pattern around the pith. The leaf's vascular tissue is not peripherally arranged, it is spread throughout the leaf in veins. The petiole, which is the stalk that joins a leaf to a stem, has vascular bundles but not in a peripheral arrangement. The root has a central vascular cylinder, not a peripheral arrangement.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : STEM"}, {"id": "objective>Biology>2000>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question. <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The substance labelled II originates from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">III and IV</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The substance labelled II is oxygen. Note that in photosynthesis, the oxygen given off comes from water (IV). During photosynthesis, the oxygen released comes primarily from water molecules (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O) rather than from the Elodea plant itself. In the process of photosynthesis, plants use sunlight to convert water and carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) into glucose (a form of sugar) and oxygen (O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). The oxygen gas released as a byproduct of this process originates from the splitting of water molecules within the plant cells, not from any external source such as the Elodea plant itself.</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>2000>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/> The gas occupying the space labelled I is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is oxygen, tiny bubbles of the gas are seen to appear  on the surface of the leaves which will eventually move up to the test tube. To be sure about the gas, it is tested with a glowing splinter. It was observed that it rekindles the glowing splinter, hence confirms it as oxygen.</div>", "topic": "RESPIRATION : THE MECHANISM OF GASEOUS EXCHANGE IN PLANTS AND MAMMALS"}, {"id": "objective>Biology>2000>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The scapula and the ischium are part of the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">pectoral girdle </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pelvic girdle </div>", "<div style=\"font-family:Cambria;font-size:17px;\">appendicular skeleton</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hind limb</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The left and right clavicle and scapula make up the pectoral girdle. <br/> The ischium forms the lower and back part of the hip bone, which is part of the pelvis. They are all part of the Appendicular skeleton.</div>", "topic": "SUPPORT AND MOVEMENT : TYPES AND FUNCTIONS OF THE SKELETON"}, {"id": "objective>Biology>2000>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Bacteria in the large intestine of man are important in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">synthesis of vitamins K and B<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">digestion of vegetables </div>", "<div style=\"font-family:Cambria;font-size:17px;\">synthesis of vitamins A and D</div>", "<div style=\"font-family:Cambria;font-size:17px;\">absorption of water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bacteria in the large intestine of man are important in the synthesis of vitamins K and B2. They also help in the digestion of cellulose.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2000>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Short-sightedness can be corrected by lenses which are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">convex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biconvex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">plano-convex</div>", "<div style=\"font-family:Cambria;font-size:17px;\">concave</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Short-sightedness, also known as myopia, is a condition where the eye can see close objects clearly but distant objects appear blurred. This is due to the eye's lens focusing light in front of the retina, rather than directly on it. This can be corrected by using concave lenses. Concave lenses are thinner at the center than at the edges, and they spread out light rays so that they can be focused on the retina correctly.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2000>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The inner ear contains two main organs namely the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">eardrum and eustachian tube</div>", "<div style=\"font-family:Cambria;font-size:17px;\">cochlea and semi-circular canals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oval window and ossicles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pinna and cochlea</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The inner ear contains two main parts: the cochlea, which is involved in hearing, and the semicircular canals, which are involved in balance. The cochlea is a spiral-shaped organ that transforms sound vibrations from the middle ear into electrical signals. The semicircular canals are three fluid-filled tubes that provide the brain with information about orientation to maintain balance.</div>", "topic": "COORDINATION AND CONTROL : THE SENSE ORGANS"}, {"id": "objective>Biology>2000>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For growth to occur in organisms, the rate of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">food storage must be low </div>", "<div style=\"font-family:Cambria;font-size:17px;\">catabolism must exceed that of anabolism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">anabolism must exceed that of catabolism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">food storage must be high</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Growth in organisms occurs when the rate of anabolism (the process of building up or synthesizing compounds in the body, which requires energy) exceeds that of catabolism (the process of breaking down compounds in the body, which releases energy). This is because growth involves the synthesis of new structures and tissues, which is an anabolic process.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>2000>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The production of violet colouration, when dilute NaOH solution is added to a solution of food substance, followed by drops of 1% CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> solution while shaking, indicates the presence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">protein</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbohydrates </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fats</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reducing sugar</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The test described in the question is the Biuret test, which is used to detect the presence of proteins. When a solution of a protein is treated with dilute NaOH and then with a few drops of 1% CuSO4 solution, a violet coloration is produced. This is due to the formation of a complex between the copper ions and the peptide bonds in the protein.</div>", "topic": "NUTRITION : ANIMAL NUTRITION"}, {"id": "objective>Biology>2000>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The greatest amount of energy will be obtained by the oxidation of 100kg of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">meat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">butter</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sugar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">biscuits</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Butter, which is a fat, contains more energy per gram than meat (protein), sugar (carbohydrate), or biscuits (a mix of carbohydrates, fats, and proteins). This is because fats have a higher energy content per gram than proteins or carbohydrates. Therefore, the greatest amount of energy would be obtained by the oxidation of 100kg of butter.</div>", "topic": "ECOLOGY : ENERGY FLOW IN THE ECOSYSTEM"}, {"id": "objective>Biology>2000>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The chamber of the mammalian heart with the thickest wall is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">right ventricle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">left auricle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">right auricle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">left ventricle</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The left ventricle has the thickest wall because it needs to pump blood to the rest of the body, against higher pressure, so it's stronger and more muscular than the other chambers.</div>", "topic": "TRANSPORT : MAMMALIAN CIRCULATORY SYSTEM"}, {"id": "objective>Biology>2000>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Serum differs from blood plasma because it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">contains blood cells and fibrinogen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">contains soluble food and mineral salts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lacks the blood protein, fibrinogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lacks blood cells and albumin</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Serum is essentially blood plasma without fibrinogen and other clotting factors. It is the component that is left after allowing the blood to clot and removing the clot. Therefore, it lacks the blood protein, fibrinogen.</div>", "topic": "TRANSPORT : MATERIALS FOR TRANSPORTATION"}, {"id": "objective>Biology>2000>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the diagram below to answer this question. <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The part labelled II is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">mesocarp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pericarp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">endocarp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">epicarp</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is the mesocarp, In a typical fruit the mesocarp is the middle layer. It is found inbetween  the endocarp and epicarp.</div>", "topic": "INTERNAL STRUCTURE OF A FLOWERING PLANT : LEAF"}, {"id": "objective>Biology>2000>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the diagram below to answer this question. <br/>  <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The fruit represented is mainly dispersed by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">wind</div>", "<div style=\"font-family:Cambria;font-size:17px;\">birds</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is dispersed by water, it is dispersed by water due to its fibrous mesocarp trapping air enables it to remain afloat.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2000>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an experiment to estimate the volume of air in a soil sample using a measuring cylinder, it was found that:  <br/> Initial volume of water = p cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  Volume of soil before mixing with water = q cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  Final volume of water after adding soil = r cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  From the data above, which of the following deductions is correct?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">r = p + q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">r > p + q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">q = r - p</div>", "<div style=\"font-family:Cambria;font-size:17px;\">r < p + q </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">After mixing the air present in the soil will escape due to stirring of the soil in the water, the final volume will be less. <br/> Therefore, r < p + q.</div>", "topic": "SOIL : CHARACTERISTICS OF DIFFERENT TYPES OF SOIL"}, {"id": "objective>Biology>2000>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An ecological succession often leads to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in species diversity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in species diversity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">an unstable community </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the dispersal of species</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ecological succession is the process of change in the species structure of an ecological community over time. It often leads to an increase in species diversity as the environment becomes more stable and can support a wider range of species.</div>", "topic": "THE ECOLOGY OF POPULATIONS : ECOLOGICAL SUCCESSION"}, {"id": "objective>Biology>2000>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Atmospheric nitrogen is converted to soil nitrogen for plant use by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitrification and combustion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">putrefaction and lightning </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lightning and nitrification</div>", "<div style=\"font-family:Cambria;font-size:17px;\">combustion and putrefaction </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Atmospheric nitrogen is converted to soil nitrogen for plant use by the process of nitrification and through lightning. Nitrification is a process by which specific bacteria convert different forms of nitrogen-containing compounds. Atmospheric nitrogen is converted into nitrates by lightning, which can then be used by plants.</div>", "topic": "NUTRITION : PLANT NUTRITION"}, {"id": "objective>Biology>2000>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. High birth rate and high immigration rate.  <br/> II. Low birth rate and high immigration rate.  <br/> III. Low mortality rate and low emigration rate.  <br/>  IV. High mortality rate and high emigration rate.  <br/> Which combination of the above can cause rapid overcrowding in climax biotic communities and human settlements?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">High birth rate and low mortality rate can cause rapid overcrowding in climax biotic communities and human settlements. High birth rate means more individuals are being added to the population, and low mortality rate means fewer individuals are leaving or dying, leading to an increase in population size.</div>", "topic": "THE ECOLOGY OF POPULATIONS : POPULATION DENSITY AND OVERCROWDING"}, {"id": "objective>Biology>2000>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Use the graph below to answer this question. <br/>  <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> The soil becomes toxic to plants when the concentration of its essential elements is in the range labelled </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The part labelled \"IV\" depict that the soil essential concentration element, has increased maximally with very low plant growth graphically.</div>", "topic": "SOIL : SOIL FERTILITY"}, {"id": "objective>Biology>2000>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> Use the graph below to answer this question. <br/>  <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The range at which soil essential elements concentration is recorded for optimal plant growth is marked </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">III gives the best range for optimal growth.At the part labelled \"III\", the soil essential elements concentration, has increased maximally with a very low plant growth showing optimal growth.</div>", "topic": "SOIL : SOIL FERTILITY"}, {"id": "objective>Biology>2000>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following growth activities in plants is brought about by gibberellins?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Rapid cell division</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tropic response</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cell elongation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Main cell elongation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gibberellins are plant hormones that regulate growth and influence various developmental processes, including stem elongation, germination, dormancy, flowering, sex expression, enzyme induction, and leaf and fruit senescence.</div>", "topic": "GROWTH : MEANING OF GROWTH"}, {"id": "objective>Biology>2000>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are adaptations of animals to aquatic habitats?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gills, streamlined bodies and lateral line</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lateral line, streamlined bodies and lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gills, scaly skin and lungs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Gills, streamlined bodies and spiracles</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aquatic animals have adapted to their environment in several ways. Gills are used for respiration in water, streamlined bodies help to reduce resistance when moving through water, and the lateral line system is a sense organ in aquatic organisms, especially fish, that detects movement and vibration in the surrounding water. Lungs and spiracles are adaptations for air-breathing animals, not aquatic ones.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2000>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is an adaptation of forest species?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Few stomata</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Thick bark</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Buttress roots </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Reduced leaves</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Buttress roots are large, wide roots on all sides of a shallowly rooted tree. Typically, they are found mainly in large trees located in the tropical rain forest and they provide structural support. Few stomata, thick bark, and reduced leaves are adaptations to dry conditions, not forest conditions.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTATIONS IN ORGANISMS"}, {"id": "objective>Biology>2000>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a food chain, each succeeding level in a forward direction represents </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the number of individuals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the number of individuals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the biomass of individuals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a gain in the total energy being transferred</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a food chain, each succeeding level in a forward direction represents a decrease in the number of individuals. This is due to the fact that as energy is transferred up the food chain, there is a loss of energy at each trophic level due to the energy used for metabolic processes and heat loss. As a result, there is less energy available to support the same number of individuals at higher trophic levels, leading to a decrease in the number of individuals.</div>", "topic": "ECOLOGY : FOOD CHAINS FOOD WEBS AND TROPHIC LEVELS"}, {"id": "objective>Biology>2000>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The disaster that would have the least destructive impact on animal life and balance in nature is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chemical pollution </div>", "<div style=\"font-family:Cambria;font-size:17px;\">forest fires</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oil spillage </div>", "<div style=\"font-family:Cambria;font-size:17px;\">grasshopper pests</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Grasshopper pests would have the least destructive impact on animal life and balance in nature. While they can cause significant damage to crops, their impact on animal life and the overall balance of nature is less severe than the other options. Chemical pollution and oil spillage can have long-term, widespread effects on multiple species and ecosystems, while forest fires can result in the loss of habitat for many species.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2000>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The legs and beak of an egret resemble those of the heron because they</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">both feed on fishes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are both birds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">occupy similar niche</div>", "<div style=\"font-family:Cambria;font-size:17px;\">occupy the same trophic level</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The legs and beak of an egret resemble those of the heron because they occupy similar niches. In ecology, a niche refers to the role and position a species has in its environment, including what it eats and how it interacts with other species. Both egrets and herons are wading birds that feed on fish and other small aquatic animals, so they have similar adaptations, such as long legs for wading in water and long, pointed beaks for catching prey.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2000>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The factors that determines the distribution of vegetation zones are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">temperature, light, rain and humidity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">light, humidity, air and mist</div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature, light , air and humidity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">humidity, snow, frost and dew </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The distribution of vegetation zones is determined by several factors including temperature, light, rain and humidity. These factors influence the types of plants that can survive and thrive in a particular area. For example, temperature affects the rate of photosynthesis and plant growth, light is necessary for photosynthesis, rain provides water which is essential for plant life, and humidity affects the rate of evaporation and transpiration.</div>", "topic": "ECOLOGY : FACTORS AFFECTING THE DISTRIBUTION OF ORGANISMS"}, {"id": "objective>Biology>2000>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cross between an albino female and a genetically normal male will result in offspring that are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all albino</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all phenotypically normal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">all genetically normal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">half albino and half normal</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Albinism is a recessive trait, which means that an individual must inherit two copies of the albino gene (one from each parent) to express the trait. If a genetically normal male (who does not carry the albino gene) mates with an albino female (who carries two copies of the albino gene), all of their offspring will inherit one normal gene from the father and one albino gene from the mother. This means that all of the offspring will be carriers of the albino gene, but they will not express the trait because they also have a normal gene. Therefore, they will all be phenotypically normal.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2000>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pollutants that contribute to the depletion of the ozone layer in the atmosphere are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">radioactive materials</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxides of sulphur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxides of carbon</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorofluorocarbons</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorofluorocarbons (CFCs) are the main pollutants that contribute to the depletion of the ozone layer in the atmosphere. CFCs are compounds that contain chlorine, fluorine, and carbon. They are used in air conditioning systems, refrigerators, and aerosol propellants. When CFCs are released into the atmosphere, they can rise to the stratosphere where they are broken down by solar radiation, releasing chlorine atoms. These chlorine atoms can catalyze the destruction of ozone, leading to the thinning of the ozone layer, also known as the ozone hole.</div>", "topic": "HUMANS AND ENVIRONMENT : POLLUTION AND ITS CONTROL"}, {"id": "objective>Biology>2000>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The surest way to combine the best qualities of both parents in the offspring is by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cross-breeding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">inbreeding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">selective breeding </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pure breeding </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cross-breeding is the surest way to combine the best qualities of both parents in the offspring. This is because cross-breeding involves the mating of two different species or breeds, which allows for the combination of the best traits of both parents. Inbreeding, selective breeding, and pure breeding do not necessarily combine the best qualities of both parents.</div>", "topic": "HEREDITY : APPLICATION OF THE PRINCIPLES OF HEREDITY"}, {"id": "objective>Biology>2000>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Blood grouping in human beings is derived from combinations of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">two different alleles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">four different alleles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">three different alleles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">two different genes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alleles combinations are responsible for blood groups. There are three common blood type alleles: A, B, and O. Humans all have two alleles, one inherited from each parent. The possible combinations of the three alleles are; OO; AO; BO; AB; AA; BB.</div>", "topic": "HEREDITY : INHERITANCE OF CHARACTERS IN ORGANISMS"}, {"id": "objective>Biology>2000>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The older fossil-bearing rocks, in contrast to the more recent ones, are more likely to contain</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">animal rather than plant remains</div>", "<div style=\"font-family:Cambria;font-size:17px;\">invertebrates rather than birds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flowering plants rather than mosses</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reptiles rather than fishes </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The older fossil-bearing rocks, in contrast to the more recent ones, are more likely to contain invertebrates rather than birds. This is because invertebrates evolved before birds in the history of life on Earth. The other options are incorrect because they do not accurately represent the types of organisms that would be found in older versus more recent fossil-bearing rocks.</div>", "topic": "EVOLUTION : EVIDENCE OF EVOLUTION"}, {"id": "objective>Biology>2000>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a group of male Agama lizards, the one with the brightest head colour is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dominant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">youngest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">oldest </div>", "<div style=\"font-family:Cambria;font-size:17px;\">largest</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a group of male Agama lizards, the one with the brightest head colour is usually the dominant one. This is because in many animal species, bright colours are often a sign of dominance and are used to attract mates and intimidate rivals. Therefore, the correct answer is 'dominant'.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2000>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Examples of water-borne and sex-linked diseases are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">taeniasis and malaria </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cholera and gonorrhoea</div>", "<div style=\"font-family:Cambria;font-size:17px;\">typhoid and syphilis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dracunculiasis and haemophilia</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water-borne diseases are diseases that are transmitted through contaminated water. Dracunculiasis, also known as Guinea worm disease, is a water-borne disease. Sex-linked diseases are genetic diseases that are determined by the sex chromosomes. Haemophilia is a sex-linked disease because it is usually passed from mother to son on the X chromosome. Therefore, the correct answer is 'dracunculiasis and haemophilia'.</div>", "topic": "HUMANS AND ENVIRONMENT : DISEASES"}, {"id": "objective>Biology>2000>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The mutation theory of organic evolution was propounded by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gregor Mendel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Hugo de Vries</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Jean Lamarck</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Charles Darwin</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mutation theory of organic evolution was propounded by Hugo de Vries. This theory, also known as the mutation theory of evolution, proposes that new species are formed from the sudden and drastic changes in the genes of an individual, which are then passed on to its offspring. Therefore, the correct answer is 'Hugo de Vries'.</div>", "topic": "EVOLUTION : THEORIES OF EVOLUTION"}, {"id": "objective>Biology>2000>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A certain savanna grasshopper changes colour from green during the rainy season to brown during the dry season and black after the dry season bush fires. The reason for these colour changes is that the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">grasshopper is getting older</div>", "<div style=\"font-family:Cambria;font-size:17px;\">environment temperature is changing </div>", "<div style=\"font-family:Cambria;font-size:17px;\">grasshopper is avoiding predation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">grasshopper is frequently moulting </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The grasshopper changes its color to blend in with its environment and avoid being noticed by predators. This is a survival strategy known as camouflage. During the rainy season, the environment is green, so the grasshopper is green. During the dry season, the environment turns brown, so the grasshopper turns brown. After bush fires, the environment is black, so the grasshopper turns black.</div>", "topic": "ADAPTATION FOR SURVIVAL : ADAPTIVE COLOURATION AND ITS FUNCTIONS"}, {"id": "objective>Biology>2000>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Complex social behaviour and organization are found mostly in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">insects</div>", "<div style=\"font-family:Cambria;font-size:17px;\">birds</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reptiles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">mammals</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mammals, particularly primates, are known for their complex social behavior and organization. They live in groups with defined roles and hierarchies, communicate in sophisticated ways, and exhibit a wide range of behaviors related to cooperation, competition, and social learning. While insects, birds, and reptiles can also exhibit social behavior, it is generally not as complex as that of mammals.</div>", "topic": "ADAPTATION FOR SURVIVAL : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS"}, {"id": "objective>Biology>2000>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following structural features are adapted for uses other than water conservation?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Succulent stems</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Scales in animals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Spines in plants</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Feathers in birds</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Feathers in birds are adapted for uses other than water conservation. They are primarily used for flight and insulation, but also play roles in display during courtship and in protecting the bird's skin from damage. The other options listed - succulent stems, scales in animals, and spines in plants - are all adaptations primarily related to water conservation.</div>", "topic": "ADAPTATION FOR SURVIVAL : STRUCTURAL ADAPTIONS IN ORGANISMS"}];
